from dataclasses import dataclass, field
from datetime import date
from typing import Literal

@dataclass
class Subprocessor:
    name: str
    role: str  # e.g. "Cloud hosting (AWS)", "Logging (Datadog)"
    tier: Literal[1, 2]
    dpa_with_vendor: bool
    security_cert: str | None  # "SOC2_TypeII" | "ISO27001" | None
    data_regions: list[str]    # e.g. ["eu-west-1", "eu-central-1"]
    breach_chain_hours: int | None  # hours to notify primary vendor

@dataclass
class ReviewOutcome:
    subprocessor: Subprocessor
    status: Literal["approved", "conditional", "rejected", "watch_list"]
    findings: list[str] = field(default_factory=list)
    next_review: date | None = None

def review_subprocessor(sp: Subprocessor, allowed_regions: set[str]) -> ReviewOutcome:
    findings = []
    if not sp.dpa_with_vendor:
        findings.append("No DPA between vendor and subprocessor")
    if sp.tier == 1 and sp.security_cert is None:
        findings.append("Missing security certification for Tier 1 subprocessor")
    disallowed = set(sp.data_regions) - allowed_regions
    if disallowed:
        findings.append(f"Data processed in disallowed regions: {disallowed}")
    if sp.breach_chain_hours is not None and sp.breach_chain_hours > 12:
        findings.append(f"Breach notification chain {sp.breach_chain_hours}h may not support 24h SLA")

    if not findings:
        status = "approved"
    elif len(findings) == 1 and "certification" in findings[0]:
        status = "conditional"  # give 90-day remediation window
    else:
        status = "rejected"
    return ReviewOutcome(subprocessor=sp, status=status, findings=findings)

allowed = {"eu-west-1", "eu-central-1", "us-east-1"}
sps = [
    Subprocessor("AWS", "Cloud hosting", 1, True, "SOC2_TypeII", ["eu-west-1"], 4),
    Subprocessor("Datadog", "Logging", 1, True, None, ["us-east-1"], 8),
    Subprocessor("SomeCo", "Analytics", 2, False, None, ["ap-southeast-1"], None),
]
for sp in sps:
    outcome = review_subprocessor(sp, allowed)
    print(f"{sp.name}: {outcome.status} | {outcome.findings}")
